// POST /token - Exchange authorization code for access token
app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret, refresh_token } = req.body;

  // Also support client credentials in Authorization header
  let authenticatedClientId = client_id;
  let authenticatedClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const [headerClientId, headerClientSecret] = decoded.split(':');
    authenticatedClientId = authenticatedClientId || headerClientId;
    authenticatedClientSecret = authenticatedClientSecret || headerClientSecret;
  }

  // Validate client credentials
  const client = clients[authenticatedClientId];
  if (!client || client.client_secret !== authenticatedClientSecret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication failed.' });
  }

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res, client, code, redirect_uri);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res, client, refresh_token);
  } else {
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Only authorization_code and refresh_token grant types are supported.' });
  }
});

function handleAuthorizationCodeGrant(req, res, client, code, redirect_uri) {
  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Authorization code is required.' });
  }

  const authCode = authorizationCodes[code];

  // Validate authorization code exists
  if (!authCode) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code.' });
  }

  // Check if code has been used (prevent replay attacks)
  if (authCode.used) {
    // If code was already used, revoke all tokens issued with this code
    console.log(`[SECURITY] Authorization code reuse detected: ${code}. Revoking associated tokens.`);
    delete authorizationCodes[code];
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code has already been used.' });
  }

  // Check if code has expired
  if (Date.now() > authCode.expires_at) {
    delete authorizationCodes[code];
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code has expired.' });
  }

  // Validate client_id matches
  if (authCode.client_id !== client.client_id) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code was not issued to this client.' });
  }

  // Validate redirect_uri matches
  if (redirect_uri && authCode.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'redirect_uri does not match.' });
  }

  // Mark code as used
  authCode.used = true;

  // Generate tokens
  const accessToken = generateToken(32);
  const newRefreshToken = generateToken(32);
  const expiresIn = 3600; // 1 hour

  accessTokens[accessToken] = {
    client_id: client.client_id,
    username: authCode.username,
    scope: authCode.scope,
    created_at: Date.now(),
    expires_at: Date.now() + (expiresIn * 1000)
  };

  refreshTokens[newRefreshToken] = {
    client_id: client.client_id,
    username: authCode.username,
    scope: authCode.scope,
    created_at: Date.now(),
    expires_at: Date.now() + (30 * 24 * 60 * 60 * 1000) // 30 days
  };

  console.log(`[TOKEN] Access token issued for user: ${authCode.username}, client: ${client.client_id}`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: newRefreshToken,
    scope: authCode.scope.join(' ')
  });
}

function handleRefreshTokenGrant(req, res, client, refreshToken) {
  if (!refreshToken) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'refresh_token is required.' });
  }

  const storedRefreshToken = refreshTokens[refreshToken];

  if (!storedRefreshToken) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid refresh token.' });
  }

  if (Date.now() > storedRefreshToken.expires_at) {
    delete refreshTokens[refreshToken];
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Refresh token has expired.' });
  }

  if (storedRefreshToken.client_id !== client.client_id) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Refresh token was not issued to this client.' });
  }

  // Rotate refresh token
  delete refreshTokens[refreshToken];

  const newAccessToken = generateToken(32);
  const newRefreshToken = generateToken(32);
  const expiresIn = 3600;

  accessTokens[newAccessToken] = {
    client_id: client.client_id,
    username: storedRefreshToken.username,
    scope: storedRefreshToken.scope,
    created_at: Date.now(),
    expires_at: Date.now() + (expiresIn * 1000)
  };

  refreshTokens[newRefreshToken] = {
    client_id: client.client_id,
    username: storedRefreshToken.username,
    scope: storedRefreshToken.scope,
    created_at: Date.now(),
    expires_at: Date.now() + (30 * 24 * 60 * 60 * 1000)
  };

  console.log(`[TOKEN] Access token refreshed for user: ${storedRefreshToken.username}, client: ${client.client_id}`);

  res.json({
    access_token: newAccessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: newRefreshToken,
    scope: storedRefreshToken.scope.join(' ')
  });
}

// Token introspection endpoint (RFC 7662)
app.post('/introspect', (req, res) => {
  const { token, token_type_hint } = req.body;

  // Authenticate client
  let clientId, clientSecret;
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    [clientId, clientSecret] = decoded.split(':');
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  const client = clients[clientId];
  if (!client || client.client_secret !== clientSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (!token) {
    return res.json({ active: false });
  }

  const tokenData = accessTokens[token];
  if (!tokenData || Date.now() > tokenData.expires_at) {
    return res.json({ active: false });
  }

  res.json({
    active: true,
    scope: tokenData.scope.join(' '),
    client_id: tokenData.client_id,
    username: tokenData.username,
    token_type: 'Bearer',
    exp: Math.floor(tokenData.expires_at / 1000),
    iat: Math.floor(tokenData.created_at / 1000)
  });
});

// Token revocation endpoint (RFC 7009)
app.post('/revoke', (req, res) => {
  const { token, token_type_hint } = req.body;

  // Authenticate client
  let clientId, clientSecret;
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    [clientId, clientSecret] = decoded.split(':');
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  const client = clients[clientId];
  if (!client || client.client_secret !== clientSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (token) {
    if (accessTokens[token]) {
      delete accessTokens[token];
      console.log(`[REVOKE] Access token revoked`);
    }
    if (refreshTokens[token]) {
      delete refreshTokens[token];
      console.log(`[REVOKE] Refresh token revoked`);
    }
  }

  // Always respond with 200 per RFC 7009
  res.status(200).send();
});

// Protected resource endpoint (for testing)
app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Bearer token required.' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens[token];

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token not found.' });
  }

  if (Date.now() > tokenData.expires_at) {
    delete accessTokens[token];
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token has expired.' });
  }

  const user = users[tokenData.username];
  res.json({
    sub: user.username,
    name: user.name,
    scope: tokenData.scope.join(' ')
  });
});

// OAuth server metadata endpoint (RFC 8414)
app.get('/.well-known/oauth-authorization-server', (req, res) => {
  const baseUrl = `${req.protocol}://${req.get('host')}`;
  res.json({
    issuer: baseUrl,
    authorization_endpoint: `${baseUrl}/authorize`,
    token_endpoint: `${baseUrl}/token`,
    introspection_endpoint: `${baseUrl}/introspect`,
    revocation_endpoint: `${baseUrl}/revoke`,
    userinfo_endpoint: `${baseUrl}/userinfo`,
    response_types_supported: ['code'],
    grant_types_supported: ['authorization_code', 'refresh_token'],
    token_endpoint_auth_methods_supported: ['client_secret_basic', 'client_secret_post'],
    scopes_supported: ['read', 'write', 'admin']
  });
});

