// Cleanup expired tokens periodically
setInterval(() => {
  const now = Date.now();
  let cleanedCodes = 0, cleanedTokens = 0, cleanedRefresh = 0;

  for (const [code, data] of Object.entries(authorizationCodes)) {
    if (now > data.expires_at) {
      delete authorizationCodes[code];
      cleanedCodes++;
    }
  }
  for (const [token, data] of Object.entries(accessTokens)) {
    if (now > data.expires_at) {
      delete accessTokens[token];
      cleanedTokens++;
    }
  }
  for (const [token, data] of Object.entries(refreshTokens)) {
    if (now > data.expires_at) {
      delete refreshTokens[token];
      cleanedRefresh++;
    }
  }

  if (cleanedCodes + cleanedTokens + cleanedRefresh > 0) {
    console.log(`[CLEANUP] Removed ${cleanedCodes} codes, ${cleanedTokens} access tokens, ${cleanedRefresh} refresh tokens`);
  }
}, 60 * 1000); // Every minute

